rule.example:
import java.util.Calendar
import java.time.LocalDateTime

class Bad {
    fun currentMillis(): Long {
        return Calendar.getInstance().timeInMillis  // violation
    }
}

class Good {
    fun currentMillis(): Long {
        return System.currentTimeMillis()  // ok: no Calendar created
    }

    fun now(): LocalDateTime {
        return LocalDateTime.now()  // ok: java.time API
    }
}
